	<item>
		<title>The Business of Cricket: How Leagues Are Changing India’s Sports Landscape</title>
		<link>https://c11cl.com/the-business-of-cricket-how-leagues-are-changing-indias-sports-landscape/</link>
					<comments>https://c11cl.com/the-business-of-cricket-how-leagues-are-changing-indias-sports-landscape/#respond</comments>
		
		<dc:creator><![CDATA[Admin]]></dc:creator>
		<pubDate>Wed, 11 Feb 2026 07:05:11 +0000</pubDate>
				<category><![CDATA[C11CL News]]></category>
		<category><![CDATA[C11CL]]></category>
		<category><![CDATA[C11CL registration]]></category>
